module.exports = (function() {
  const disableBinding = process.env.DISABLE_FNV_BINDING === 'true';
  if (Number(process.versions.napi) >= 6 && !disableBinding) {
    try {
      return require('./binding')
    } catch {
      return require('./js-impl')
    }
  }
  return require('./js-impl')
})()
